function excelDateToJSDate(serial) {
  return new Date((serial - 25569) * 86400 * 1000);
}

const today = new Date();
today.setHours(0,0,0,0);

return items.map(item => {
  const dueDateJS = excelDateToJSDate(item.json.DueDate);
  dueDateJS.setHours(0,0,0,0);
  const diff = Math.ceil((dueDateJS - today) / (1000 * 60 * 60 * 24));

  return {
    json: {
      ...item.json,
      daysRemaining: diff
    }
  };
});

let html = `
<h3>Upcoming Payment Due Alerts</h3>
<table border="1" cellpadding="8" cellspacing="0" style="border-collapse:collapse;font-family:Arial;width:100%">
<tr style="background:#f2f2f2">
<th>###</th>
<th>Location</th>
<th>Division</th>
<th>Description</th>
<th>ISP</th>
<th>Mbps</th>
<th>Circuit ID</th>
<th>Network Type</th>
<th>Rate</th>
<th>Tax +18%</th>
<th>Total</th>
<th>Total Per Annum</th>
<th>DueDate</th>
<th>Payment Cycle</th>
<th>Days Remaining</th>
<th>New Circuit ID</th>
</tr>`;

items.forEach(i => {
  html += `<tr>
<td>${i.json["###"] || 'N/A'}</td>
<td>${i.json["Location"] || 'N/A'}</td>
<td>${i.json["Division"] || 'N/A'}</td>
<td>${i.json["Descripton"] || 'N/A'}</td>
<td>${i.json["ISP"] || 'N/A'}</td>
<td>${i.json["Mbps"] || 'N/A'}</td>
<td>${i.json["Circui ID"] || 'N/A'}</td>
<td>${i.json["Network Type"] || 'N/A'}</td>
<td>${i.json["Rate"] || 0}</td>
<td>${i.json["Tax +18%"] || 0}</td>
<td>${i.json["Total"] || 0}</td>
<td>${i.json["Total Per Annum"] || 0}</td>
<td>${i.json["DueDate"] || 'N/A'}</td>
<td>${i.json["Payment Cycle"] || 'N/A'}</td>
<td style="color:red;font-weight:bold">${i.json.daysRemaining}</td>
<td>${i.json["New Circuit ID"] || 'N/A'}</td>
</tr>`;
});

html += `</table><br><br>Regards,<br>IT Team (systems)`;

// Safe minDays calculation
const validItems = items.filter(i => i.json.daysRemaining !== undefined);
if (!validItems.length) return [];

const minDays = Math.min(...validItems.map(i => i.json.daysRemaining));

const subjectMap = {
  5: '⏳ Payment Due in 5 Days – Action Required',
  4: '⚠️ Payment Due in 4 Days',
  3: '🚨 Payment Due in 3 Days – Urgent',
  2: '🔥 Payment Due in 2 Days – Immediate Attention',
  1: '❗ FINAL REMINDER – Payment Due Tomorrow'
};

return [{
  json: {
    graphBody: {
      message: {
        subject: subjectMap[minDays] || 'Payment Due Alert',
        body: {
          contentType: 'HTML',
          content: html
        },
        toRecipients: [
          { emailAddress: { address: 'systems@ninestars.in' } },
          { emailAddress: { address: 'prem.d@ninestars.in' } }
        ]
      },
      saveToSentItems: true
    }
  }
}];
